module fpga_mvp_top (
    input  wire        clk,
input  wire        rst_n,
    input  wire [31:0] data_in,
    input  wire        valid_in,
    output reg  [31:0] data_out,
    output reg         valid_out,
    output wire        ready
);

    // State machine
    localparam IDLE    = 3'd0;
    localparam PROCESS = 3'd1;
    localparam DONE    = 3'd2;

    reg [2:0] state;
    reg [2:0] next_state;

    // Sacred constants
