    wire [31:0] phoenix;

fpga_mvp_sacred_constants sacred_inst (
        .phi(phi),
        .phi_sq(phi_sq),
        .phi_inv_sq(phi_inv_sq),
        .trinity(trinity),
        .phoenix(phoenix)
    );

    assign ready = (state == IDLE);

    // State register
always @(posedge clk or negedge rst_n) begin
if (!rst_n)
            state <= IDLE;
        else
            state <= next_state;
    end

    // Next state logic
